import { useEffect, useState } from "react";

function Dashboard() {
    const [threads, setThreads] = useState([]);
    const [news, setNews] = useState([]);
    const [matches, setMatches] = useState([]);
    const [events, setEvents] = useState([]);

    useEffect(() => {
        fetch("/api/threads").then(res => res.json()).then(setThreads);
        fetch("/api/news").then(res => res.json()).then(setNews);
        fetch("/api/matches").then(res => res.json()).then(setMatches);
        fetch("/api/events").then(res => res.json()).then(setEvents);
    }, []);

    return (
        <div style={{ display: "flex", gap: "20px", padding: "20px" }}>
            {/* Column 1: Threads */}
            <div style={{ flex: 1 }}>
                <h3>Threads</h3>
                <ul>
                    {threads.map(t => (
                        <li key={t.id}>{t.title}</li>
                    ))}
                </ul>
            </div>

            {/* Column 2: News */}
            <div style={{ flex: 1 }}>
                <h3>News</h3>
                <ul>
                    {news.map(n => (
                        <li key={n.id}>{n.headline}</li>
                    ))}
                </ul>
            </div>

            {/* Column 3: Matches */}
            <div style={{ flex: 1 }}>
                <h3>Matches</h3>
                <ul>
                    {matches.map(m => (
                        <li key={m.id}>
                            {m.teamA} vs {m.teamB} —{" "}
                            {new Date(m.matchTime).toLocaleString()}
                        </li>
                    ))}
                </ul>
            </div>

            {/* Column 4: Events */}
            <div style={{ flex: 1 }}>
                <h3>Events</h3>
                <ul>
                    {events.map(e => (
                        <li key={e.id}>
                            {e.name} — {new Date(e.eventDateTime).toLocaleString()}
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
}

export default Dashboard;
